import{_ as i,o as t,c as a,a0 as s}from"./chunks/framework.B_R3rS_4.js";const g=JSON.parse('{"title":"Neural RTI & rtiprep Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"technical/neural-rti.md","filePath":"technical/neural-rti.md"}'),r={name:"technical/neural-rti.md"};function n(l,e,o,p,h,c){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="neural-rti-rtiprep-architecture" tabindex="-1">Neural RTI &amp; <code>rtiprep</code> Architecture <a class="header-anchor" href="#neural-rti-rtiprep-architecture" aria-label="Permalink to &quot;Neural RTI &amp; `rtiprep` Architecture&quot;">​</a></h1><p>Neural RTI is a state-of-the-art representation format that replaces traditional mathematical fitting models (like Polynomials or Spherical Harmonics) with a compact neural network representation.</p><hr><h2 id="_1-the-neural-rti-concept" tabindex="-1">1. The Neural RTI Concept <a class="header-anchor" href="#_1-the-neural-rti-concept" aria-label="Permalink to &quot;1. The Neural RTI Concept&quot;">​</a></h2><p>Instead of storing large sets of coefficients (e.g., 16 coefficients for HSH) per pixel, Neural RTI splits the representation into two components:</p><ol><li><strong>Latent Map (H x W x 4):</strong> A 4-dimensional optimized latent grid texture stored as a standard 8-bit RGBA image. This map compresses the local geometric and reflectance properties of each pixel.</li><li><strong>Decoder MLP (Multilayer Perceptron):</strong> A global, lightweight neural network (~13 KB JSON file, 448 parameters) shared by all pixels.</li></ol><p>During rendering, the shader evaluates the MLP feed-forward pass for each pixel:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Color(RGB) = Decoder_MLP(z_latent, l_light)</span></span></code></pre></div><p>Where:</p><ul><li><code>z_latent</code> is the 4D latent vector fetched from the texture.</li><li><code>l_light</code> is the 3D normalized light direction vector [x, y, z].</li></ul><hr><h2 id="_2-packaging-with-rtiprep" tabindex="-1">2. Packaging with <code>rtiprep</code> <a class="header-anchor" href="#_2-packaging-with-rtiprep" aria-label="Permalink to &quot;2. Packaging with `rtiprep`&quot;">​</a></h2><p>The <code>rtiprep</code> command-line utility converts raw latent maps and decoder weights into a single pyramidal tiled <strong>Cloud-Optimized GeoTIFF (COG)</strong>. This file format allows the viewer to request individual 256x256 tiles of the latent map on-demand using HTTP Range Requests.</p><h3 id="critical-downsampling-constraints" tabindex="-1">Critical Downsampling Constraints <a class="header-anchor" href="#critical-downsampling-constraints" aria-label="Permalink to &quot;Critical Downsampling Constraints&quot;">​</a></h3><p>Pyramidal TIFFs store downscaled overviews of the image (LODs) to speed up rendering when zoomed out. However, downscaling a latent map poses a unique mathematical challenge:</p><ul><li><strong>No Bilinear Blending on CPU:</strong> By default, image pyramids are built using bilinear interpolation. If we linearly average neighboring latent vectors, the blended values represent a &quot;garbage&quot; input to the non-linear decoder MLP, yielding black or corrupted pixels. <code>rtiprep</code> must use strict <strong>Nearest-Neighbor downsampling</strong> (<code>xDraw.NearestNeighbor</code>) for the overviews.</li><li><strong>NRGBA Canvas Preservation:</strong> Standard Go image scaling writes to <code>image.RGBA</code>, which uses alpha-premultiplication. This multiplies the first three latent channels (R, G, B) by the fourth channel (A), distorting the latent representation. <code>rtiprep</code> allocates an <code>image.NRGBA</code> canvas to bypass Go&#39;s draw library alpha conversion and keep values intact.</li></ul><hr><h2 id="_3-webgl-real-time-rendering" tabindex="-1">3. WebGL Real-Time Rendering <a class="header-anchor" href="#_3-webgl-real-time-rendering" aria-label="Permalink to &quot;3. WebGL Real-Time Rendering&quot;">​</a></h2><p>Once the client downloads the tiled GeoTIFF and weights, it streams them to the WebGL fragment shader.</p><h3 id="nearest-gpu-texture-filtering" tabindex="-1">Nearest GPU Texture Filtering <a class="header-anchor" href="#nearest-gpu-texture-filtering" aria-label="Permalink to &quot;Nearest GPU Texture Filtering&quot;">​</a></h3><p>At fractional zoom levels (where texture pixels do not align 1:1 on the screen), the GPU automatically blends neighboring texels if <code>LinearFilter</code> is active. Just like CPU bilinear downsampling, this corrupts the MLP outputs. The loader forces Three.js to use strict nearest-neighbor texture filtering:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.rtiType </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  tex.minFilter </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> THREE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.NearestFilter;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  tex.magFilter </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> THREE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.NearestFilter;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="estimating-pseudo-normals-finite-differences" tabindex="-1">Estimating Pseudo-Normals (Finite Differences) <a class="header-anchor" href="#estimating-pseudo-normals-finite-differences" aria-label="Permalink to &quot;Estimating Pseudo-Normals (Finite Differences)&quot;">​</a></h3><p>Because Neural RTI does not store physical surface coefficients directly, we compute the intensity gradients at normal incidence L0 = (0, 0, 1) on the GPU using <strong>finite differences</strong> (epsilon = 0.005) to support advanced visualization modes:</p><ol><li><p><strong>MLP Evaluations:</strong></p><ul><li>I0 = Luminance( MLP(z_latent, [0, 0, 1]) )</li><li>Ix = Luminance( MLP(z_latent, [epsilon, 0, sqrt(1 - epsilon^2)]) )</li><li>Iy = Luminance( MLP(z_latent, [0, epsilon, sqrt(1 - epsilon^2)]) )</li></ul></li><li><p><strong>Gradients:</strong></p><ul><li>gx = (Ix - I0) / epsilon</li><li>gy = (Iy - I0) / epsilon</li></ul></li><li><p><strong>Normal Vector (N):</strong> We scale the gradients (e.g. by <code>4.0</code>) to enhance geometric details and contrast:</p><ul><li>N = normalize([-gx * 4.0, -gy * 4.0, 1.0])</li></ul></li></ol><p>This normal vector is then used to compute specular highlights (Glossy), RGB normals (Normals Mode), or steepness heatmaps.</p>',26)])])}const u=i(r,[["render",n]]);export{g as __pageData,u as default};
